sql:
SELECT name 
FROM manufacturers 
WHERE manufacturer_id = (SELECT manufacturer_id FROM vehicles WHERE vehicle_id = 0);

external_knowledge:
- 'Not too pricey' refers to a vehicle with a price less than or equal to $50,000;
- 'Smooth to shift gears' implies that the vehicle has an 'Automatic' transmission;
- 'Highly rated by users' means the average rating is 4.5 or higher out of 5.

sql:
SELECT vehicle_id, price
FROM vehicles
WHERE price > (SELECT AVG(price) FROM vehicles);

SELECT model
FROM vehicles
WHERE vehicle_id > 1;

SELECT type
FROM transmissions
WHERE gears > 5;

SELECT DISTINCT name 
FROM manufacturers 
WHERE country = 'US';

external_knowledge:
- "shining stars in the city’s fuel efficiency race" refers to vehicles with high city fuel efficiency;
- "city mileage that soars above thirty miles per gallon" indicates a mpg_city value greater than 30;
- "speediest gas guzzling tortoises" is a metaphor for less fuel-efficient vehicles in the queried set;
- "most fuel-sipping hares" refers to the vehicles with the highest fuel efficiency in the queried set.

sql:
SELECT vehicles.vehicle_id, transmissions.type
FROM vehicles
INNER JOIN transmissions ON vehicles.transmission_id = transmissions.transmission_id;

SELECT v.vehicle_id, v.make, v.model, v.model_year, vf.feature, vf.feature_type
FROM vehicles v
JOIN vehicle_features vf ON v.vehicle_id = vf.vehicle_id;

